import{_ as i,o as n,c as a,ai as h}from"./chunks/framework.CJDL-GS7.js";const g=JSON.parse('{"title":"Làm bài tập","description":"","frontmatter":{},"headers":[],"relativePath":"assignment-guide.md","filePath":"assignment-guide.md","lastUpdated":null}'),o={name:"assignment-guide.md"};function r(e,t,l,s,c,p){return n(),a("div",null,[...t[0]||(t[0]=[h('<h1 id="lam-bai-tap" tabindex="-1">Làm bài tập <a class="header-anchor" href="#lam-bai-tap" aria-label="Permalink to &quot;Làm bài tập&quot;">​</a></h1><p>Bài tập được giáo viên giao trực tiếp cho lớp học. Mỗi bài tập có hạn nộp và sẽ được giáo viên chấm điểm sau khi nộp.</p><h2 id="xem-danh-sach-bai-tap" tabindex="-1">Xem danh sách bài tập <a class="header-anchor" href="#xem-danh-sach-bai-tap" aria-label="Permalink to &quot;Xem danh sách bài tập&quot;">​</a></h2><ol><li>Vào <strong>Bài tập</strong> trên sidebar</li><li>Danh sách hiển thị tất cả bài tập từ các lớp đang tham gia</li><li>Các bài tập được sắp xếp theo hạn nộp gần nhất</li></ol><h3 id="trang-thai-bai-tap" tabindex="-1">Trạng thái bài tập <a class="header-anchor" href="#trang-thai-bai-tap" aria-label="Permalink to &quot;Trạng thái bài tập&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Trạng thái</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td>🟡 <strong>Chưa nộp</strong></td><td>Bài tập chưa được làm, còn trong hạn</td></tr><tr><td>🔴 <strong>Quá hạn</strong></td><td>Đã qua hạn nộp mà chưa nộp</td></tr><tr><td>🟢 <strong>Đã nộp</strong></td><td>Đã nộp, đang chờ giáo viên chấm</td></tr><tr><td>✅ <strong>Đã chấm</strong></td><td>Giáo viên đã chấm xong, có điểm và nhận xét</td></tr></tbody></table><h2 id="nop-bai-tap" tabindex="-1">Nộp bài tập <a class="header-anchor" href="#nop-bai-tap" aria-label="Permalink to &quot;Nộp bài tập&quot;">​</a></h2><ol><li>Nhấn vào bài tập cần nộp</li><li>Đọc kỹ <strong>đề bài</strong> và <strong>hướng dẫn</strong> của giáo viên</li><li>Điền nội dung bài làm vào ô soạn thảo</li><li>Đính kèm file nếu yêu cầu (hỗ trợ PDF, Word, ảnh)</li><li>Nhấn <strong>Nộp bài</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">Lưu ý quan trọng</p><ul><li>Sau khi nhấn <strong>Nộp bài</strong>, bạn <strong>không thể chỉnh sửa</strong> lại trừ khi giáo viên cho phép nộp lại.</li><li>Kiểm tra kỹ bài làm trước khi nộp.</li><li>Nộp bài trước hạn để tránh sự cố kết nối mạng phút chót.</li></ul></div><h2 id="xem-điem-va-nhan-xet" tabindex="-1">Xem điểm và nhận xét <a class="header-anchor" href="#xem-điem-va-nhan-xet" aria-label="Permalink to &quot;Xem điểm và nhận xét&quot;">​</a></h2><p>Sau khi giáo viên chấm bài:</p><ol><li>Vào <strong>Bài tập → tab Đã chấm</strong></li><li>Nhấn vào bài tập để xem điểm chi tiết</li><li>Đọc <strong>nhận xét</strong> của giáo viên để rút kinh nghiệm</li></ol>',12)])])}const m=i(o,[["render",r]]);export{g as __pageData,m as default};
